        "dispatch_result_path": dispatch_summary
            .and_then(|summary| summary.dispatch_result_path.clone()),
        "dispatch_status": dispatch_summary
            .map(|summary| summary.dispatch_status.clone()),
        "dispatch_target": dispatch_summary
